const dossier_id = $json.dossier_id || 'TEST-DOSSIER-' + Date.now();
const topic_seed = $json.topic_seed || '';
const route_id = $json.route_id || 'ROUTE_PHASE1_STANDARD';
const route_lane = $json.route_lane || 'topic_to_script';
const creator_id = $json.creator_id || 'LOCAL_TEST';
const channel_id = $json.channel_id || 'YOUTUBE';
return [{
  json: {
    workflow_id: 'CWF-110',
    workflow_name: 'topic_discovery',
    vein: 'discovery_vein',
    dossier_id: dossier_id,
    topic_seed: topic_seed,
    route_id: route_id,
    route_lane: route_lane,
    creator_id: creator_id,
    channel_id: channel_id,
    execution_timestamp: new Date().toISOString(),
    vein_stage: 'discovery',
    context: {
      audience: $json.audience || 'general',
      budget_profile: $json.budget_profile || 'standard',
      content_type: $json.content_type || 'video'
    }
  }
}];

const skills_to_call = [
  { skill_id: 'M-001', name: 'Global Trend Scanner', priority: 1 },
  { skill_id: 'M-002', name: 'Topic Opportunity Miner', priority: 2 },
  { skill_id: 'M-003', name: 'Keyword Intelligence Miner', priority: 2 },
  { skill_id: 'M-004', name: 'Audience Demographic Mapper', priority: 2 },
  { skill_id: 'M-006', name: 'Viral Pattern Detector', priority: 3 },
  { skill_id: 'M-007', name: 'Algorithm Signal Monitor', priority: 3 }
];
return [{
  json: {
    ...$json,
    skill_execution_plan: skills_to_call,
    skill_execution_mode: 'sequential_with_error_capture',
    context_packet_required: true
  }
}];

const discovery_context = {
  role_definition: 'trend_signal_aggregator',
  behavior_model: 'observational, non-judgmental signal capture',
  operating_method: 'ingest â†’ normalize â†’ attach_provenance â†’ return_signal_set',
  allowed_tools: ['deterministic_transforms', 'trend_feeds', 'registry_lookups'],
  forbidden_tools: ['premium_apis_without_approval', 'heavy_llm_calls'],
  error_escalation: 'WF-900',
  fallback_on_no_signals: 'emit_empty_board_with_status_empty',
  mutation_law: {
    reads: ['feed_registry', 'source_family_registry'],
    writes: ['dossier.discovery.trend_signals', 'dossier.discovery.topic_opportunities'],
    forbidden_overwrites: ['dossier_identity', 'approval_namespaces']
  }
};
return [{
  json: {
    ...$json,
    context_packet: discovery_context,
    context_packet_validated: true
  }
}];

const trend_signals = [
  {
    signal_id: 'SIG-' + Date.now() + '-1',
    thematic_phrase: $json.topic_seed || 'AI Technology Trends',
    mention_volume: Math.floor(Math.random() * 10000) + 1000,
    trend_direction: 'RISING',
    source_refs: ['trends_feed', 'reddit', 'twitter'],
    confidence: 0.85,
    discovery_window: '2026-03-15 to 2026-04-15'
  }
];
return [{
  json: {
    ...$json,
    trend_signals: trend_signals,
    signal_count: trend_signals.length
  }
}];

const opportunities = [
  {
    opportunity_id: 'OPP-' + Date.now() + '-1',
    topic_statement: 'How AI is Reshaping ' + ($json.topic_seed || 'Technology'),
    cluster_signals: $json.trend_signals.map(s => s.signal_id),
    cluster_confidence: 0.82,
    rationale: 'Strong signal volume with rising trend across multiple sources',
    audience_alignment: 'tech enthusiasts, creators, entrepreneurs',
    estimated_demand: 'HIGH'
  }
];
return [{
  json: {
    ...$json,
    topic_opportunities: opportunities,
    opportunity_count: opportunities.length
  }
}];

const keywords = [
  { keyword: 'AI trends 2026', search_volume: 12500, competition: 'HIGH', trend: 'RISING', intent: 'informational' },
  { keyword: 'AI creators', search_volume: 8200, competition: 'MEDIUM', trend: 'RISING', intent: 'commercial' },
  { keyword: 'AI tutorial', search_volume: 35000, competition: 'HIGH', trend: 'STABLE', intent: 'educational' }
];
return [{
  json: {
    ...$json,
    keywords: keywords,
    keyword_count: keywords.length,
    high_opportunity_keywords: keywords.filter(k => k.search_volume > 10000)
  }
}];

const audience_mapping = {
  primary_segments: [
    { segment: 'Tech Enthusiasts', size: 'Large', interest_level: 'Very High', resonance_reasons: ['Innovation focus', 'Early adopter mindset'] },
    { segment: 'Content Creators', size: 'Medium', interest_level: 'High', resonance_reasons: ['Tool exploration', 'Competitive advantage'] }
  ],
  estimated_addressable_audience: 2500000,
  cross_channel_alignment: 'YouTube trending topics in tech category'
};
return [{
  json: {
    ...$json,
    audience_mapping: audience_mapping
  }
}];

const viral_patterns = [
  { pattern_type: 'hook_structure', pattern_name: 'Surprising AI Capability Reveal', frequency_observed: 'high', success_rate: 0.78, example: 'Did you know AI can...?' }
];
return [{
  json: {
    ...$json,
    viral_patterns: viral_patterns
  }
}];

const algorithm_signals = [
  { platform: 'YouTube', signal_type: 'recommendation_friendly', strength: 'medium', reasoning: 'Topic aligns with trending education category' }
];
return [{
  json: {
    ...$json,
    algorithm_signals: algorithm_signals
  }
}];

const candidate_board = {
  instance_id: 'TCB-' + Date.now(),
  artifact_family: 'topic_candidate_board',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-110-Topic-Discovery',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: $json.topic_opportunities && $json.topic_opportunities.length > 0 ? 'CREATED' : 'EMPTY',
  payload: {
    signal_count: $json.signal_count || 0,
    opportunity_count: $json.opportunity_count || 0,
    keyword_count: $json.keyword_count || 0,
    candidates: $json.topic_opportunities || [],
    supporting_signals: {
      trends: $json.trend_signals || [],
      keywords: $json.keywords || [],
      audience: $json.audience_mapping || {},
      viral_patterns: $json.viral_patterns || [],
      algorithm_signals: $json.algorithm_signals || []
    },
    discovery_metadata: {
      route_id: $json.route_id,
      dossier_id: $json.dossier_id,
      execution_timestamp: $json.execution_timestamp
    }
  }
};
return [{ json: candidate_board }];

try {
  const packet = $json;
  if (!packet.instance_id || !packet.artifact_family || packet.status === 'EMPTY' && !packet.payload.candidates) {
    return [{ json: { validation_result: 'FAILED', error: 'Invalid packet structure', packet: packet } }];
  }
  return [{ json: { validation_result: 'SUCCESS', packet_valid: true, packet: packet } }];
} catch (e) {
  return [{ json: { validation_result: 'ERROR', error: e.message } }];
}

const dossier_delta = {
  dossier_id: $json.dossier_ref,
  namespace: 'discovery',
  mutation_timestamp: new Date().toISOString(),
  mutation_owner: 'SE-N8N-CWF-110',
  mutation_type: 'append_to_array',
  target_field: 'trend_signals_packet',
  audit_entry: {
    event: 'TOPIC_DISCOVERY_COMPLETE',
    workflow_id: 'CWF-110',
    packet_id: $json.instance_id,
    status: $json.status
  }
};
return [{ json: { dossier_delta: dossier_delta, write_to_dossier: true } }];

const packet_index_row = {
  packet_id: $json.instance_id,
  dossier_id: $json.dossier_ref,
  packet_type: $json.artifact_family,
  version: $json.schema_version,
  workflow_id: 'CWF-110',
  child_workflow_id: 'SE-N8N-CWF-110-Topic-Discovery',
  created_at: $json.created_at,
  file_path: 'C:/ShadowEmpire/n8n_user/packets/' + $json.instance_id + '.json',
  status: $json.status
};
return [{ json: { packet_index_row: packet_index_row, write_to_index: true } }];

return [{
  json: {
    workflow_id: 'CWF-110',
    execution_status: 'SUCCESS',
    next_workflow: 'CWF-120',
    candidate_board_packet: $json,
    ready_for_qualification: $json.status === 'CREATED' && $json.payload.candidates && $json.payload.candidates.length > 0
  }
}];
